#include <bits/stdc++.h>
#define int long long
using namespace std;
int t;
int qpow (int a , int b , int p) {
	int res = 1;
	while (b) {
		if (b & 1) {
			res = res * a % p;
		}
		a = a * a % p;
		b >>= 1;
	}
	return res;
}
vector <int> get (int n) {
	vector <int> factors;
	for (int i = 2; i * i <= n; i++) {
		if (n % i == 0) {
			factors.push_back(i);
			while (n % i == 0) {
				n /= i;
			}
		}
	} 
	if (n > 1) {
		factors.push_back(n);
	}
	return factors;
}
bool check (int a, int p) {
	if (a <= 1 || a >= p) {
		return false;
	}
	if (qpow (a , p - 1 , p) != 1) {
		return false;
	}
	vector <int> factors = get (p - 1);
	for (auto q : factors) {
		if (qpow (a, (p - 1) / q, p) == 1) {
			return false;
		}
	}
	return true;
}
signed main() {
	ios::sync_with_stdio (0);
	cin.tie (0), cout.tie (0);
	cin >> t;
	while (t--) {
		int a , p;
		cin >> a >> p;
		if (check (a, p)) {
			cout << "Yes\n";
		} else {
			cout << "No\n";
		}
	}
	return 0;
}
